arguments.new_str:
@using sv_c57a4d115c9a4af28872ea289e572a79.Models
@using sv_c57a4d115c9a4af28872ea289e572a79.Services
@inject InventoryService InventoryService
@inject NavigationManager Navigation

<tr>
    <EditForm Model="EditModel" OnValidSubmit="Save" FormName="@($"edit-{Product.Id}")">
        <DataAnnotationsValidator />
        <td>
            <InputText @bind-Value="EditModel!.Name" class="form-control form-control-sm" />
            <ValidationMessage For="() => EditModel!.Name" />
        </td>
        <td>
            <InputNumber @bind-Value="EditModel!.Quantity" class="form-control form-control-sm" />
            <ValidationMessage For="() => EditModel!.Quantity" />
        </td>
        <td>
            <InputNumber @bind-Value="EditModel!.UnitPrice" class="form-control form-control-sm" />
            <ValidationMessage For="() => EditModel!.UnitPrice" />
        </td>
        <td>
            <InputSelect @bind-Value="EditModel!.Category" class="form-select form-select-sm">
                <option value="">-- Select --</option>
                <option value="Electronics">Electronics</option>
                <option value="Clothing">Clothing</option>
                <option value="Food">Food</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => EditModel!.Category" />
        </td>
        <td>
            <button type="submit" class="btn btn-success btn-sm me-1">Save</button>
            <button type="button" class="btn btn-secondary btn-sm" @onclick="Cancel">Cancel</button>
        </td>
    </EditForm>
</tr>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    private Product? EditModel { get; set; }

    protected override void OnInitialized()
    {
        EditModel = new Product
        {
            Id = Product.Id,
            Name = Product.Name,
            Quantity = Product.Quantity,
            UnitPrice = Product.UnitPrice,
            Category = Product.Category
        };
    }

    private async Task Save()
    {
        await InventoryService.UpdateAsync(EditModel!);
        Navigation.NavigateTo("/inventory", forceLoad: true);
    }

    private void Cancel()
    {
        Navigation.NavigateTo("/inventory", forceLoad: true);
    }
}

