 @page "/inventory"
 @using sv_c57a4d115c9a4af28872ea289e572a79.Models
 @using sv_c57a4d115c9a4af28872ea289e572a79.Services
 @inject InventoryService InventoryService
 @inject NavigationManager Navigation

 <PageTitle>Inventory</PageTitle>

 <h1>Inventory</h1>

 @* MODE 1 — Static SSR "Quick Add" form *@
 <div class="card mb-4">
     <div class="card-header">Quick Add Product</div>
     <div class="card-body">
         <EditForm Model="NewProduct" OnValidSubmit="AddProduct" FormName="quick-add" Enhance>
             <DataAnnotationsValidator />
             <ValidationSummary />
             <div class="row g-2 align-items-end">
                 <div class="col-md-3">
                     <label class="form-label">Name</label>
                     <InputText @bind-Value="NewProduct!.Name" class="form-control form-control-sm" />
                 </div>
                 <div class="col-md-2">
                     <label class="form-label">Quantity</label>
                     <InputNumber @bind-Value="NewProduct!.Quantity" class="form-control form-control-sm" />
                 </div>
                 <div class="col-md-2">
                     <label class="form-label">Unit Price</label>
                     <InputNumber @bind-Value="NewProduct!.UnitPrice" class="form-control form-control-sm" />
                 </div>
                 <div class="col-md-2">
                     <label class="form-label">Category</label>
                     <InputSelect @bind-Value="NewProduct!.Category" class="form-select form-select-sm">
                         <option value="">-- Select --</option>
                         <option value="Electronics">Electronics</option>
                         <option value="Clothing">Clothing</option>
                         <option value="Food">Food</option>
                         <option value="Other">Other</option>
                     </InputSelect>
                 </div>
                 <div class="col-md-2">
                     <button type="submit" class="btn btn-primary btn-sm">Add Product</button>
                 </div>
             </div>
         </EditForm>
     </div>
 </div>

 @* MODE 2 — Product table with interactive inline editing *@
 <table class="table table-striped">
     <thead>
         <tr>
             <th>Name</th>
             <th>Quantity</th>
             <th>Unit Price</th>
             <th>Category</th>
             <th>Actions</th>
         </tr>
     </thead>
     <tbody>
         @if (Products is not null)
         {
             @foreach (var product in Products)
             {
                 if (EditingProductId == product.Id)
                 {
                     <EditRow @rendermode="InteractiveServer"
                              Product="product" />
                 }
                 else
                 {
                     <tr>
                         <td>@product.Name</td>
                         <td>@product.Quantity</td>
                         <td>@product.UnitPrice.ToString("C")</td>
                         <td>@product.Category</td>
                         <td>
                             <a href="/inventory?edit=@product.Id" class="btn btn-outline-primary btn-sm">Edit</a>
                         </td>
                     </tr>
                 }
             }
         }
     </tbody>
 </table>

 @code {
     [SupplyParameterFromForm(FormName = "quick-add")]
     private Product? NewProduct { get; set; }

     [SupplyParameterFromQuery(Name = "edit")]
     private int? EditingProductId { get; set; }

     private List<Product>? Products { get; set; }

     protected override async Task OnInitializedAsync()
     {
         NewProduct ??= new();
         Products = await InventoryService.GetAllAsync();
     }

     private async Task AddProduct()
     {
         await InventoryService.AddAsync(NewProduct!);
         Navigation.NavigateTo("/inventory", forceLoad: true);
     }
 }

